// Calculate the timestamp for 48 hours ago in ISO format
const since = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
return [{ json: { since, ran_at: new Date().toISOString() } }];

const posts = $input.first().json;
const since = $('Code: Set Time Window').first().json.since;

if (!Array.isArray(posts) || posts.length === 0) {
  return [{ json: { _no_posts: true, since } }];
}

return posts.map(p => ({
  json: {
    post_id:      p.id              || '',
    post_urn:     p.linkedin_post_id || '',
    post_content: p.linkedin_draft  || '',
    post_url:     p.source_post_url || '',
    post_topic:   p.idea_title      || 'accounting automation',
    _no_posts:    false
  }
}));

const commentsData  = $input.all()[0]?.json?.elements || [];
const reactionsData = $input.all()[1]?.json?.elements || [];
const post          = $('Process Each Post').first().json;

const people = new Map();

for (const el of commentsData) {
  const actor = el['actor~'] || el.actor || {};
  if (!actor.id) continue;
  const firstName = actor.firstName?.localized?.en_US || actor.firstName || '';
  const lastName  = actor.lastName?.localized?.en_US  || actor.lastName  || '';
  const name = (firstName + ' ' + lastName).trim();
  if (!name) continue;
  people.set(actor.id, {
    linkedin_id:      actor.id,
    name,
    headline:         actor.headline?.localized?.en_US || actor.headline || '',
    profile_url:      actor.publicProfileUrl || '',
    location:         actor.location?.name || '',
    engagement_type:  'comment',
    comment_text:     el.message?.text || '',
    engagement_bonus: 10,
    post_urn:         post.post_urn,
    post_content:     post.post_content,
    post_url:         post.post_url,
    post_topic:       post.post_topic
  });
}

for (const el of reactionsData) {
  const actor = el['actor~'] || el.actor || {};
  if (!actor.id || people.has(actor.id)) continue;
  const firstName = actor.firstName?.localized?.en_US || actor.firstName || '';
  const lastName  = actor.lastName?.localized?.en_US  || actor.lastName  || '';
  const name = (firstName + ' ' + lastName).trim();
  if (!name) continue;
  people.set(actor.id, {
    linkedin_id:      actor.id,
    name,
    headline:         actor.headline?.localized?.en_US || actor.headline || '',
    profile_url:      actor.publicProfileUrl || '',
    location:         actor.location?.name || '',
    engagement_type:  'reaction',
    comment_text:     '',
    engagement_bonus: 0,
    post_urn:         post.post_urn,
    post_content:     post.post_content,
    post_url:         post.post_url,
    post_topic:       post.post_topic
  });
}

console.log('Post:', post.post_urn, '| Unique people:', people.size);
if (people.size === 0) return [{ json: { _empty: true, post_urn: post.post_urn } }];
return Array.from(people.values()).map(p => ({ json: p }));

const person   = $('Process Each Person').first().json;
const existing = $input.first().json;
const alreadyIn = Array.isArray(existing) && existing.length > 0;
return [{ json: { ...person, _already_exists: alreadyIn } }];

const person = $('Code: Merge Existence Check').first().json;
const apollo = $input.first().json?.person || {};
const apolloOrg = apollo.organization || {};

const headlineParts = person.headline || '';
const parsedCompany = headlineParts.includes(' at ')
  ? headlineParts.split(' at ').pop().trim()
  : headlineParts.includes(' | ')
    ? headlineParts.split(' | ').pop().trim()
    : '';

return [{
  json: {
    ...person,
    email:         apollo.email           || '',
    company_name:  apolloOrg.name         || parsedCompany,
    job_title:     apollo.title           || person.headline,
    company_size:  apolloOrg.estimated_num_employees || null,
    country:       apollo.country         || person.location,
    industry:      apolloOrg.industry     || '',
    tech_keywords: (apolloOrg.keywords    || []).join(', ')
  }
}];

const person   = $('Code: Build Score Prompt').first().json;
const response = $input.first().json;

let scoreData = { score: 0, tier: 'COLD', qualification_reasons: [], red_flags: [], ideal_outreach_angle: '' };
try {
  const raw = response?.content?.[0]?.text || '{}';
  scoreData = JSON.parse(raw.replace(/```json?\n?/g, '').replace(/```/g, '').trim());
} catch(e) {
  console.error('Score parse error:', e.message);
}

const totalScore = (scoreData.score || 0) + (person.engagement_bonus || 0);
return [{
  json: {
    ...person,
    score:                 scoreData.score || 0,
    tier:                  totalScore >= 75 ? 'HOT' : totalScore >= 60 ? 'WARM' : 'COLD',
    qualification_reasons: scoreData.qualification_reasons || [],
    red_flags:             scoreData.red_flags || [],
    ideal_outreach_angle:  scoreData.ideal_outreach_angle || '',
    total_score:           totalScore
  }
}];

const person   = $('Code: Build DM Prompt').first().json;
const response = $input.first().json;
let dm = (response?.content?.[0]?.text || '').trim();
if (dm.length > 280) dm = dm.slice(0, 277) + '...';
return [{ json: { ...person, dm_draft: dm, dm_char_count: dm.length } }];

const allItems = $input.all();
const saved = allItems.filter(i => i.json && !i.json.error && i.json.id);
const hot  = saved.filter(i => i.json.tier === 'HOT');
const warm = saved.filter(i => i.json.tier === 'WARM');

if (saved.length === 0) {
  return [{ json: { _no_leads: true, total_saved: 0, hot_count: 0, warm_count: 0, message: '' } }];
}

const hotLines = hot.map(i =>
  '* ' + i.json.name + ' — ' + (i.json.company_name || '') + ' (' + i.json.score + '/100)\n  DM: ' + (i.json.dm_draft || '')
).join('\n\n');

const warmLines = warm.map(i =>
  '* ' + i.json.name + ' — ' + (i.json.company_name || '') + ' (' + i.json.score + '/100)\n  DM: ' + (i.json.dm_draft || '')
).join('\n\n');

let msg = 'LinkedIn Lead Scan Complete\n';
msg += saved.length + ' qualified leads saved\n';
msg += 'HOT: ' + hot.length + '  |  WARM: ' + warm.length + '\n\n';
if (hot.length  > 0) msg += 'HOT (send today):\n'    + hotLines  + '\n\n';
if (warm.length > 0) msg += 'WARM (send within 48h):\n' + warmLines + '\n\n';
msg += 'All leads saved in Supabase (status: pending_outreach)';

return [{ json: { _no_leads: false, total_saved: saved.length, hot_count: hot.length, warm_count: warm.length, message: msg } }];
